"use client";

import { useState } from "react";
import { createClient } from "@/lib/supabase/client";
import { toast } from "@/components/ui/Toast";

interface Props {
  initialOpenRouter?: string | null;
  initialTelegram?: string | null;
  initialStripe?: string | null;
  aiModel?: string | null;
}

export default function IntegrationsSettings({
  initialOpenRouter,
  initialTelegram,
  initialStripe,
  aiModel,
}: Props) {
  const [openRouterKey, setOpenRouterKey] = useState(initialOpenRouter ?? "");
  const [telegramToken, setTelegramToken] = useState(initialTelegram ?? "");
  const [stripeAccount, setStripeAccount] = useState(initialStripe ?? "");
  const [saving, setSaving] = useState(false);

  const openRouterConnected = Boolean(openRouterKey);

  const saveIntegrations = async () => {
    setSaving(true);
    try {
      if (openRouterKey && openRouterKey !== initialOpenRouter) {
        const orRes = await fetch("https://openrouter.ai/api/v1/auth/key", {
          headers: { Authorization: `Bearer ${openRouterKey}` },
        });
        if (!orRes.ok) {
          throw new Error("A chave do OpenRouter (IA) é inválida ou expirou.");
        }
      }

      if (telegramToken && telegramToken !== initialTelegram) {
        const tgRes = await fetch(
          `https://api.telegram.org/bot${telegramToken}/getMe`
        );
        const tgData = (await tgRes.json()) as { ok?: boolean };
        if (!tgData.ok) {
          throw new Error("O Token do Telegram é inválido.");
        }
      }

      const supabase = createClient();
      const {
        data: { user },
      } = await supabase.auth.getUser();

      if (!user) throw new Error("Não autenticado");

      const { error } = await supabase
        .from("therapists")
        .update({
          openrouter_key_hash: openRouterKey || null,
          telegram_bot_token: telegramToken || null,
          stripe_account_id: stripeAccount || null,
        })
        .eq("user_id", user.id);

      if (error) throw error;

      toast.success("Integrações validadas e atualizadas com sucesso!");
    } catch (e: unknown) {
      const err = e as Error;
      toast.error(err.message ?? "Erro ao salvar integrações");
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="flex flex-col gap-4">
      <IntegrationItem
        name="OpenRouter (IA / LLM)"
        description={`Modelo ativo: ${aiModel ?? "Não definido"}`}
        connected={openRouterConnected}
        value={openRouterKey}
        onChange={setOpenRouterKey}
        placeholder="Opcional (usa a chave padrão da plataforma Psique)"
        type="password"
      />

      <IntegrationItem
        name="Telegram Bot"
        description="Token do seu bot gerado via @BotFather"
        connected={Boolean(telegramToken)}
        value={telegramToken}
        onChange={setTelegramToken}
        placeholder="123456789:ABCDefghIJKlmnopQRSTuvwxYZ"
        type="password"
      />

      <IntegrationItem
        name="Stripe Connect"
        description="ID da sua conta Stripe para recebimentos"
        connected={Boolean(stripeAccount)}
        value={stripeAccount}
        onChange={setStripeAccount}
        placeholder="acct_1Ou..."
        type="text"
      />

      <div className="mt-2 flex justify-end">
        <button
          type="button"
          onClick={saveIntegrations}
          disabled={saving}
          className={`rounded-xl px-6 py-2.5 text-[13px] font-semibold transition-all ${
            saving
              ? "cursor-not-allowed border border-[var(--color-border-subtle)] bg-[var(--color-surface)] text-[var(--color-text-muted)]"
              : "bg-[var(--color-brand)] text-[#060E09] hover:bg-[var(--color-brand-hover)]"
          }`}
        >
          {saving ? "Salvando..." : "Salvar Integrações"}
        </button>
      </div>
    </div>
  );
}

function IntegrationItem({
  name,
  description,
  connected,
  value,
  onChange,
  placeholder,
  type,
}: {
  name: string;
  description: string;
  connected: boolean;
  value: string;
  onChange: (v: string) => void;
  placeholder: string;
  type: string;
}) {
  return (
    <div className="flex flex-col gap-3 border-b border-[var(--color-border-subtle)] py-4">
      <div className="flex items-center justify-between gap-3">
        <div>
          <div className="text-[14px] font-medium text-[var(--color-text-primary)]">
            {name}
          </div>
          <div className="mt-0.5 text-[12px] text-[var(--color-text-muted)]">
            {description}
          </div>
        </div>

        <span
          className={`inline-flex items-center gap-1.5 rounded-full border px-3 py-0.5 text-[11px] font-medium ${
            connected
              ? "border-[rgba(82,183,136,.3)] bg-[rgba(82,183,136,.12)] text-[var(--color-brand)]"
              : "border-[#f87171]/30 bg-[#f87171]/12 text-[#f87171]"
          }`}
        >
          <span
            className={`h-[5px] w-[5px] rounded-full ${
              connected ? "bg-[var(--color-brand)]" : "bg-[#f87171]"
            }`}
          />
          {connected ? "Conectado" : "Desconectado"}
        </span>
      </div>

      <input
        type={type}
        value={value}
        onChange={(e) => onChange(e.target.value)}
        placeholder={placeholder}
        className="w-full rounded-lg border border-[var(--color-border-subtle)] bg-[var(--color-bg-base)] px-3.5 py-2.5 text-[13px] text-[var(--color-text-primary)] outline-none transition-colors placeholder:text-[var(--color-text-muted)] focus:border-[var(--color-border-strong)]"
      />
    </div>
  );
}
